const express = require('express');  // Importing Express framework to create server and routes  
const socketIo = require("socket.io");    // Socket IO library for real-time communication between client & servers (websockets)
var cors=require('cors')                 // To handle CORS in NodeJS, allows requests from different origins 
let app = express();                      // Initialize Express server  
app.use(express.json());                // Middleware to parse JSON bodies of incoming request (useful for POST)   
// Use cors middle ware so we can accept cross origin resource sharing on our socket connection, this is necessary because the browser will not allow us if CORS settings are incorrectly configured in Express server 
app.use(cors())                          // Enable Cross-Origin Resource Sharing (CORS), allows requests from different origins  
let http = require('http').Server(app);    // Create HTTP Server and attach it to our express app, this is necessary for socket I/O setup because the server must have a listener 
const io = new SocketIo.Server(http)      // Initialize Socket IO on top of Express's http server  
let { v4: uuidv4 }=require('uuid');       // Importing UUID library to generate unique id for each user and session   
app.set("socketio", io);                 // Set socket instance in express app so that it can be used by other parts of the application 
  
// Define a route handler (POST) which will accept username & score from client, validate them on server side before storing into database for future reference and scoring system   
app.post('/addPlayer', function(req, res){     // Route to handle POST request with JSON data containing player's details 
   let {username ,score} = req.body;           // Destructuring the username & score from client-side body of incoming HTTP Request (JSON)   
      if(!uuidv4() || !username ){             // Checking for untrusted input and using secure platform APIs, this is necessary to prevent game auth bypass  
         return res.status(501).send('Invalid Input');  }             
       else {                                   // If validated successfully then store player's details into database (useful if we want a leaderboard system)   
           let data={username,score};            // Create an object to hold the username & score  
          io.emit("addPlayer",data);             // Emit this event on socket connection with all connected clients and pass player's details as payload 
         res.status(201).send('Successfully added'); }    });